function PermanentContractForm({ form, onChange, onSave, onCancel, me, readOnly }) {
  const disabled = readOnly;
  const set = (k) => (e) => onChange({ ...form, [k]: e.target.value });
  const canEditContract = !readOnly && (me.role === "admin" || me.role === "hrManager");
  return (
    <EditContractCtx.Provider value={canEditContract}>
    <div style={cs}>
      <h3 style={{ textAlign: "center", marginBottom: 4 }}>PERMANENT CONTRACT OF EMPLOYMENT</h3>
      <div style={{ display: "flex", gap: 10, alignItems: "center", marginBottom: 10, flexWrap: "wrap" }}>
        <span className="badge">{form.version || "v1.0"}</span>
        {!readOnly && canEditContract && <label className="fld" style={{ margin: 0, flex: 1, maxWidth: 220 }}><span style={{ fontSize: 11 }}>Version / reference</span>
          <input className="inp" style={{ fontSize: 11 }} value={form.version || ""} onChange={set("version")} /></label>}
        {!readOnly && canEditContract && <span className="muted small">Click "Edit clause" to customise wording for this contract.</span>}
      </div>
      <p style={{ textAlign: "center", fontSize: 12, marginBottom: 14 }}>Memorandum of an Agreement entered between MERRYLIGHT ENTERPRISES [PRIVATE] LIMITED (Contract Employer) and:</p>
      <div className="fgrid" style={{ marginBottom: 14 }}>
        <label className="fld"><span>Surname</span><input className="inp" value={form.surname || ""} onChange={set("surname")} disabled={disabled} /></label>
        <label className="fld"><span>First name(s)</span><input className="inp" value={form.firstName || ""} onChange={set("firstName")} disabled={disabled} /></label>
        <label className="fld"><span>Date of birth</span><input className="inp" type="date" value={form.dob || ""} onChange={set("dob")} disabled={disabled} /></label>
        <label className="fld"><span>ID number</span><input className="inp" value={form.idNumber || ""} onChange={set("idNumber")} disabled={disabled} /></label>
        <label className="fld"><span>Grade</span><input className="inp" value={form.grade || ""} onChange={set("grade")} disabled={disabled} /></label>
        <label className="fld"><span>Occupation / Role</span><input className="inp" value={form.occupation || ""} onChange={set("occupation")} disabled={disabled} /></label>
        <label className="fld"><span>Department</span><input className="inp" value={form.department || ""} onChange={set("department")} disabled={disabled} /></label>
        <label className="fld"><span>Engagement date</span><input className="inp" type="date" value={form.engagementDate || ""} onChange={set("engagementDate")} disabled={disabled} /></label>
      </div>
      <ContractSummaryTable noticeText="3 months' notice" />
      <ContractClause title="Duration" clauseKey="duration" form={form} onChange={onChange} readOnly={readOnly}>The Contract Employer shall employ the Assignee and the Assignee shall serve the Contract Employer on a permanent basis subject to the terms and conditions set out herein.</ContractClause>
      <ContractClause title="Days to be worked" clauseKey="days_to_be_worked" form={form} onChange={onChange} readOnly={readOnly}>Minimum 48 hours per week. Farm Operations: 6 days/week 06:30–15:00 or 07:30–16:00 (½ hour tea break). Guards: 4 days/weekday shift 06:00–18:00 or night shift 18:00–06:00. Drivers: 4 days/weekday 04:30–16:30.</ContractClause>
      <ContractClause title="Wages" clauseKey="wages" form={form} onChange={onChange} readOnly={readOnly}>Wages paid monthly as per NEC Horticulture stipulation. Allowances for transport, accommodation, fuel, lights, dog handling, firearm or travel paid as per CBA.</ContractClause>
      <ContractClause title="Annual leave" clauseKey="annual_leave" form={form} onChange={onChange} readOnly={readOnly}>0.096 days per day worked (2.5 days per month), paid monthly.</ContractClause>
      <ContractClause title="Sick leave" clauseKey="sick_leave" form={form} onChange={onChange} readOnly={readOnly}>As per statutory regulations, granted with medical certificate.</ContractClause>
      <ContractClause title="Overtime" clauseKey="overtime" form={form} onChange={onChange} readOnly={readOnly}>Not exceeding 12 hours per week at applicable rate.</ContractClause>
      <ContractClause title="Termination" clauseKey="termination" form={form} onChange={onChange} readOnly={readOnly}>3 months' notice by either party.</ContractClause>
      <ContractClause title="Protective clothing &amp; Gumboots" clauseKey="protective_clothing__amp__gumb" form={form} onChange={onChange} readOnly={readOnly}>Remain property of employer. Gumboots become employee's property after 24 months.</ContractClause>
      <ContractClause title="Confidential documents" clauseKey="confidential_documents" form={form} onChange={onChange} readOnly={readOnly}>All company information shall remain confidential during and after employment.</ContractClause>
      <ContractClause title="ETI / Labour practices" clauseKey="eti___labour_practices" form={form} onChange={onChange} readOnly={readOnly}>Merrylight Enterprises is committed to complying with international best practice labour practices through ETI base code.</ContractClause>
      <ContractClause title="Relief work" clauseKey="relief_work" form={form} onChange={onChange} readOnly={readOnly}>Relief work may be requested in a higher grade; remunerated at the higher rate for that period.</ContractClause>
      <ContractClause title="Whole agreement" clauseKey="whole_agreement" form={form} onChange={onChange} readOnly={readOnly}>This agreement constitutes the whole agreement between the parties. No warranties or representations whether express or implied shall be valid unless reduced to writing and signed by both parties.</ContractClause>
      <div style={{ display: "flex", gap: 24, flexWrap: "wrap", marginBottom: 16 }}>
        <SigBlock label="Employee" sigKey="employeeSig" nameKey="employeeSigName" dateKey="employeeSigDate" form={form} onChange={onChange} readOnly={readOnly} />
        <SigBlock label="Employer" sigKey="employerSig" nameKey="employerSigName" dateKey="employerSigDate" form={form} onChange={onChange} readOnly={readOnly} />
      </div>
      <SigBlock label="Witness" sigKey="witnessSig" nameKey="witnessName" dateKey="witnessDate" form={form} onChange={onChange} readOnly={readOnly} />
      {!readOnly && <div style={{ display: "flex", gap: 8, marginTop: 14 }}><button className="btn btn-primary" style={{ width: "auto" }} onClick={() => onSave(form)}>Submit &amp; save</button><button className="btn btn-mini" onClick={onCancel}>Cancel</button></div>}
    </div>
    </EditContractCtx.Provider>
  );
}

